	return {
		url: "https://api.openai.com/v1/chat/completions",
		headers: {
			"Authorization": "Bearer " + apiKey,
			"Content-Type": "application/json"
		},
		body: JSON.stringify(body)
	};
};

exports.parseResponse = function(responseText) {
